import { readActiveStudioSession, updateActiveStudioSession, } from "../activeStudioSession.js";
import { getConfig, hasCredentials } from "../config.js";
import { emitJson } from "../output.js";
import { resolveChannel } from "../studioChannel.js";
import { createWindowCloseArbiter, killPollerProcess, killStudioWindow, } from "../studioTeardown.js";
const CLOSE_CONFIRM_TIMEOUT_MS = 8_000;
const WINDOW_KILL_DELAY_MS = 2_500;
/**
 * Subscribe to events via the channel and resolve true once a
 * `studio:window-closed` survives the refresh grace window (no
 * `session-started` re-bind follows). The channel's subscribe internally
 * fetches the stream tip, so only events produced after this call are seen.
 *
 * `onClosePage` fires the moment a `studio:session-closed` is observed: the
 * close page beacons that when the window reaches it (every close flow lands on
 * /studio/close), and it can't `window.close()` itself, so it's the primary
 * signal to force-close the parked window.
 */
function awaitWindowClosed(channel, sessionId, onClosePage) {
    return new Promise((resolve) => {
        let timedOut = false;
        const finish = (closed) => {
            arbiter.cancel();
            clearTimeout(deadline);
            sub.abort();
            resolve(closed);
        };
        const arbiter = createWindowCloseArbiter({
            onConfirmed: () => finish(true),
            onRefuted: () => {
                if (timedOut) {
                    finish(false);
                }
            },
        });
        const deadline = setTimeout(() => {
            timedOut = true;
            if (!arbiter.hasPendingCandidate()) {
                finish(false);
            }
        }, CLOSE_CONFIRM_TIMEOUT_MS);
        const sub = channel.subscribe(sessionId, (event) => {
            if (event.type === "studio:session-closed") {
                onClosePage();
            }
            arbiter.handleEvent(event);
        }, () => finish(false));
    });
}
export async function runCloseStudio() {
    const message = process.argv.slice(2).filter((a) => !a.startsWith("--"))[0];
    const record = readActiveStudioSession();
    const sessionId = record?.sessionId ?? null;
    if (!sessionId) {
        emitJson({ event: "no-active-studio" });
        process.exit(0);
    }
    // Already closed (the daemon recorded studio:window-closed when the window
    // went away, e.g. a login tab that auto-closed before this ran). The subscribe
    // below reads from the stream tip, so it would never see that past event and
    // would time out into a bogus "close-unconfirmed". Treat an already-closed
    // session as a clean no-op.
    if (record?.windowState === "closed") {
        killPollerProcess(sessionId);
        emitJson({ event: "closed", sessionId });
        process.exit(0);
    }
    const config = getConfig();
    if (!hasCredentials() || !config.apiKey) {
        killPollerProcess(sessionId);
        emitJson({ event: "close-skipped", sessionId, reason: "not-authenticated" });
        process.exit(0);
    }
    const channel = await resolveChannel(config.apiKey, config.serviceUrl);
    // Force the window closed, once. Cheap pid kill (handles the rare
    // standalone-window case) plus the channel's force-close: the daemon already
    // ran the AppleScript close server-side (no-op here), the direct channel runs
    // it now. Both best-effort.
    let forced = false;
    const forceClose = () => {
        if (forced) {
            return;
        }
        forced = true;
        killStudioWindow(sessionId);
        channel.forceCloseWindow(sessionId);
    };
    let closed;
    try {
        // Primary trigger: studio:session-closed (close page). Backstop: the timeout.
        closed = awaitWindowClosed(channel, sessionId, forceClose);
        await channel.close(sessionId, message);
    }
    catch {
        killPollerProcess(sessionId);
        emitJson({ event: "close-skipped", sessionId, reason: "session-gone" });
        process.exit(0);
    }
    const quickConfirm = await Promise.race([
        closed,
        new Promise((resolve) => {
            setTimeout(() => resolve(null), WINDOW_KILL_DELAY_MS);
        }),
    ]);
    if (quickConfirm === null) {
        // Backstop: neither session-ended nor a confirmed window-closed arrived in
        // time, so force-close anyway (no-op if session-ended already did).
        forceClose();
    }
    const confirmed = await closed;
    killPollerProcess(sessionId);
    if (confirmed) {
        updateActiveStudioSession({ windowState: "closed" });
    }
    emitJson({
        event: confirmed ? "closed" : "close-unconfirmed",
        sessionId,
    });
    channel.destroy();
    process.exit(0);
}
